import {React,useEffect,useState} from 'react'
import { Link } from 'react-router-dom'
import axios from 'axios'

export default function Wishlist() {
    const [wishlist, setWishlist] = useState([])
    const [selectedId, setSelectedId] = useState('')

    useEffect(() => {
        getData()
    }, [])

    const getData = async() => {
        const res = await axios.get('http://localhost:1700/backend/wishlist')
        setWishlist(res.data)
    }

    const handleAddToCart = async() => {
        const formdata = new FormData()
        {selectedId ? (
            formdata.append("customer_id", 0),
            formdata.append("product_id", wishlist.product_id),
            formdata.append("file", wishlist.image),
            formdata.append("product_name", wishlist.product_name),
            formdata.append("price", wishlist.price),
            formdata.append("offer", wishlist.offer)
        ) : ("")}
        const res = await axios.post("http://localhost:1700/backend/cart", formdata)
        console.log("insert", res.data)
    }
  return (
    <div>
        <div className='category-heading wishlist-div'>
            <span className='c-heading-1'>Your Wishlist</span>
        </div>
        <div className='cart-items wishlist-items'>
            {wishlist.map((obj) => (
                <div className='cart-single-item'>
                    <img src={`img/${obj.image}`} alt="list-img" className='cart-img'/>
                    
                        <div className='cart-item-details1'>
                            <p className='cart-detail1'>{obj.product_name}</p>
                            <span className='cart-price'>Rs {obj.price}/-</span>
                            <span className='cart-offer'>{obj.offer}% off</span>
                            <div className='cart-items-count'>
                                
                                <div>
                                    <Link to='/cart'><button type="button" className='addtocart-wishlist-btn' onClick={handleAddToCart}onChange={setSelectedId(obj.product_id)}>Add to Cart</button></Link>
                                    <button type="button" className='cart-remove-btn'>Remove</button>
                                </div>
                            </div>
                        </div> 
                    
                </div>
            ))}
        </div>
    </div>
  )
}
